files.flake.nix:
{
  description = "mofaflex - Factor Analysis Models";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixos-unstable";
    flake-utils.url = "github:numtide/flake-utils";
  };

  outputs = { self, nixpkgs, flake-utils }:
    flake-utils.lib.eachDefaultSystem (system:
      let
        pkgs = import nixpkgs { inherit system; };
        pyPkgs = pkgs.python311Packages;
        coreScope = { inherit (pkgs) lib fetchPypi; };

        customPackages =
          let
            callPackageWith = pkgs.lib.callPackageWith;
            pythonPackageScope =
              pyPkgs
              // coreScope
              // {
                array_api_compat = pyPkgs."array-api-compat";
                dtw_python = pyPkgs."dtw-python";
                pyro_ppl = pyPkgs."pyro-ppl";
                scikit_learn = pyPkgs."scikit-learn";
                session_info2 = pyPkgs."session-info2";
              }
              // customPackages;
          in
          {
            mudata = callPackageWith pythonPackageScope ./mudata { };
            mofaflex = callPackageWith pythonPackageScope ./mofaflex { };
          };
      in
      {
        packages = customPackages // {
          default = customPackages.mofaflex;
        };
      }
    );
}

files.mofaflex/default.nix:
{
  lib,
  buildPythonPackage,
  fetchPypi,
  hatchling,
  setuptools,
  wheel,
  anndata,
  array_api_compat,
  dtw_python,
  gpytorch,
  h5py,
  mizani,
  mudata,
  numpy,
  packaging,
  pandas,
  platformdirs,
  plotnine,
  pyro_ppl,
  scikit_learn,
  scipy,
  session_info2,
  statsmodels,
  torch,
  tqdm,
  pythonOlder,
}:

buildPythonPackage rec {
  pname = "mofaflex";
  version = "0.1.0.post1";
  pyproject = true;

  disabled = pythonOlder "3.11";

  src = fetchPypi {
    inherit pname version;
    hash = lib.fakeHash;
  };

  build-system = [
    hatchling
    setuptools
    wheel
  ];

  dependencies = [
    anndata
    array_api_compat
    dtw_python
    gpytorch
    h5py
    mizani
    mudata
    numpy
    packaging
    pandas
    platformdirs
    plotnine
    pyro_ppl
    scikit_learn
    scipy
    session_info2
    statsmodels
    torch
    tqdm
  ];

  pythonImportsCheck = [ "mofaflex" ];

  doCheck = false;

  meta = {
    description = "Factor Analysis Models";
    homepage = "https://github.com/bioFAM/mofaflex";
    license = lib.licenses.bsd3;
    maintainers = [ ];
  };
}

